const body = $json.body ?? $json;
if (body.chat_id === undefined || body.chat_id === null || body.chat_id === '') {
  throw new Error('chat_id is required');
}

const chatId = Number(body.chat_id);
if (!Number.isFinite(chatId)) {
  throw new Error('chat_id must be numeric');
}

const limitRaw = Number(body.limit ?? 8);
const limit = Math.max(1, Math.min(50, Number.isFinite(limitRaw) ? Math.floor(limitRaw) : 8));
const query = String(body.query ?? '').trim().toLowerCase();
const since = String(body.since ?? '').trim();

const whereParts = [`chat_id = ${chatId}`];
if (since) {
  whereParts.push(`date >= '${since.replace(/'/g, "''")}'`);
}

const sql = `SELECT chat_id, message_id, sender_id, chat_title, message, source, date
FROM telegram_context
WHERE ${whereParts.join(' AND ')}
ORDER BY date DESC
LIMIT ${Math.max(limit * 5, 20)};`;

return [{
  json: {
    chat_id: chatId,
    query,
    limit,
    since: since || null,
    sql
  }
}];

const prior = $('Build SQL Query').item.json;
const query = String(prior.query || '').trim().toLowerCase();
const limit = Number(prior.limit || 8);

const nowMs = Date.now();
const queryTokens = query.split(/\s+/).filter(Boolean);

function recencyWeight(dateValue) {
  if (!dateValue) return 0;
  const ts = Date.parse(dateValue);
  if (Number.isNaN(ts)) return 0;
  const ageDays = Math.max(0, (nowMs - ts) / 86400000);
  return 1 / (1 + ageDays / 7);
}

function textMatch(message) {
  if (!queryTokens.length) return 0.5;
  const msg = String(message || '').toLowerCase();
  let hits = 0;
  for (const token of queryTokens) {
    if (msg.includes(token)) hits += 1;
  }
  return hits / queryTokens.length;
}

const scored = items.map((item) => {
  const row = item.json;
  const tm = textMatch(row.message);
  const rw = recencyWeight(row.date);
  const score = Number((0.7 * tm + 0.3 * rw).toFixed(4));
  return {
    ...row,
    score
  };
});

const filtered = queryTokens.length ? scored.filter((r) => r.score > 0.15) : scored;
const top = filtered
  .sort((a, b) => b.score - a.score)
  .slice(0, limit);

return [{
  json: {
    chat_id: prior.chat_id,
    query: prior.query,
    returned: top.length,
    items: top
  }
}];
